var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"발각됐어! 달려, 꼬맹아!","JPN":"バレちゃった！　走れ、おこちゃま！","ENG":"We've been found! Run, kid!","TWN":"被發現了！小鬼快跑！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저도 알고 있어요!","JPN":"わかってるわよ！ ","ENG":"I know that already!","TWN":"我也知道！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"이번에는 지하 루트를 공략하는 카나리아─!","JPN":"今度は地下ルートを攻略するカナリア─！","ENG":"Looks like Canary Squad is taking the underground route this time–!","TWN":"這次金絲雀選擇攻陷地下路線—！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_CHEER"},{"id":"L13_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"냉정하게 분석했을 때, 이쪽 루트도 그리 승산이 높지는 않아.","JPN":"冷静に見て、こっちのルートもあんまり勝算が高くはないよ。","ENG":"Looking at it objectively, their chances of winning by taking this route aren't that high.","TWN":"但冷靜分析後可以發現，這個路線的勝算也不是很高。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"카나리아 스쿼드의 전력은 이제 두 사람뿐이지만. 챔피언의 전력은 대부분 건재하니까.","JPN":"カナリア・スクワッドの戦力はもう二人しか残っていないけど。チャンピオンの戦力はほぼそのままだからね。","ENG":"Canary Squad has only two members left, but the champion's team still has a lot of soldiers left.","TWN":"因為金絲雀小隊的戰力現在只剩下二個人，但冠軍的戰力大部分都還在。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"제길, 그 여자의 부비 트랩이 아직도 남아 있었나!","JPN":"ちくしょう、あの女のブービートラップがまだ残っていたのか！","ENG":"Dammit. That girl's booby traps are still down here!","TWN":"可惡，那個女人埋的地雷陷阱竟然還有！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L18_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"페인트가 튄 녀석들은 빠져! 우리 모습이 스트리밍에 특정되면 곤란해!","JPN":"ペイントが身体に飛び散った奴らは来るな！　俺たちの姿が配信上で特定されたら困る！","ENG":"Anyone who has paint on them, get out! We can't be seen on camera!","TWN":"有沾到油漆的傢伙都給我走開！這副模樣不能被拍到傳到網路平台上！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"나머지는 화물 엘리베이터를 지키러 간다! 움직여!","JPN":"残りは貨物用エレベーターを守りに行くぞ！　動け！","ENG":"The rest of you, guard the cargo elevator! Now, move out!","TWN":"其餘的人去守在貨梯那！行動！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그러니까, 몰래 계단으로 가자고?","JPN":"つまり、こっそり階段で行くってこと？","ENG":"So, you want to sneak up using the stairs?","TWN":"你的意思是，偷偷從樓梯上去？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"너 제정신이냐? 싸우기도 전에 탈진하려고?","JPN":"あんた本気？　疲れて戦いにすらならなくなるよ？","ENG":"Are you crazy? We'll be exhausted before we even have a chance to fight.","TWN":"你腦袋沒問題吧？這樣還沒開打就會先體力耗盡吧？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"시끄러워요. 그러게 평소에 체력 단련 좀 열심히 하라고 했잖아요.","JPN":"うるさい。だから普段から体力を鍛えろって言っていたでしょ。","ENG":"Shut it. That's why I told you to train every day.","TWN":"你別吵，所以我平常才會一直叫你要做些體能訓練的嘛。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"화물 엘리베이터는 상대도 예상하고 있을 거예요. 교전은 최대한 피해야죠.","JPN":"貨物用エレベーターは相手も予想しているはずよ。交戦はできるだけ避けないと。","ENG":"Our opponents will be expecting us to take the elevator. And we have to avoid engagements as much as possible.","TWN":"對方應該也有料到我們會搭貨梯，所以要儘量避免遇到。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 옥상까지 100층도 넘는데…!","JPN":"おい、屋上まで100階以上もあるんだぞ……！","ENG":"Hey, but there are 100 floors up to the rooftop...!","TWN":"喂，到頂樓還要爬100多樓欸……！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"걱정 마요. 적당한 층에서 엘리베이터로 갈아타면 되니까.","JPN":"心配しないで。適当な階でちゃんとエレベーターに乗るから。","ENG":"Don't worry. We'll use the elevator after going up the stairs to reach a suitable floor.","TWN":"沒事的，我們爬到合適的樓層再搭電梯上去。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"에이 씨, 그냥 얌전히 자빠져 있을걸…….","JPN":"くそぉ、ついてきたのは間違いだったかも……","ENG":"Ugh, I should've just stayed unconscious...","TWN":"可惡，早知道我就乖乖躺著就好……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 너 믿는 구석은 있는 거 맞아?! 도파민 중독 아니냐!?","JPN":"待て、何か策はあるんだろうな！？　ドーパミンにやられているんじゃないよな！？","ENG":"Hey, are you sure about this?! You're not a dopamine addict, are you?!","TWN":"喂，你有信心吼？！你該不是多巴胺中毒吧？！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"예전의 미치라면 여기서 카나리아 스쿼드의 패배를 100% 확신했을 거야!","JPN":"いつものミッチーならこの時点でカナリア・スクワッドの敗北を100％確信してたんだけど！","ENG":"The old Mitchie would've been 100% certain that Canary Squad would lose!","TWN":"如果是以前的米琪，那我100%確定金絲雀小隊會失敗！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"하지만 지금은 달라!","JPN":"でも今回は違うよ！","ENG":"But not anymore!","TWN":"但今時不同以往！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"저 두 사람은 기세를 타고 있거든!","JPN":"あの二人は波に乗っているんだもんね！","ENG":"Those two are on a roll!","TWN":"那二人現在氣勢正旺呢！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RIFLE_CHARADE_NULL_NULL","text":{"KOREA":"저기 있다! 빨리 잡아!","JPN":"あそこだ！　捕まえろ！","ENG":"There they are! Get 'em!","TWN":"在那邊！快抓住她們！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RIFLE_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L42_1","type":"dialog","speaker":"RIFLE_CHARADE_NULL_NULL","text":{"KOREA":"놓치지 마! 두 녀석만 잡으면, 우리의 승리야!","JPN":"逃すな！　あの二人を取り押さえれば、我々の勝ちだ！","ENG":"Don't let them get away! Catch them, and it'll be our victory!","TWN":"別讓人跑了！只要抓到那二個人，我們就贏了！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L47_1","type":"dialog","speaker":"RIFLE_CHARADE_NULL_NULL","text":{"KOREA":"윽!?","JPN":"うっ！？","ENG":"Ngh?!","TWN":"唔？！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SNIPER_FIRE_BIG"},{"id":"L50_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"좋아! 이쪽 둘 다 잡았어!","JPN":"よし、こっちは二人とも制圧した！","ENG":"All right! Got 'em!","TWN":"很好！這裡二個都搞定了！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L1_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"엘리베이터까지 거의 다 왔어요! 뛰어요!","JPN":"エレベーターまであと少しよ！　走って！","ENG":"We're almost at the elevator! Run!","TWN":"快到電梯了！跑！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L4_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"흔히들 그렇게 말하잖아요?","JPN":"よく言われていますよね？","ENG":"People often say this, right?","TWN":"大家不是常說……"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"샤레이드 건틀렛 리그는 스폰서빨이라고. 스폰서가 얼마나 잘 나가는지에 따라 승패가 좌우된다고.","JPN":"シャレードガントレットリーグはスポンサーゲームだって。スポンサーの良し悪しが勝敗に直結するって。","ENG":"That the Charade Gauntlet League is all about sponsors. That winning and losing all depend on how good a sponsor has their backs.","TWN":"查雷德聖鎧聯賽根本是贊助商比賽，勝敗是根據贊助商的實力而定的。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"맞는 말이에요. 다들 어느 정도는 체념하고 있었으니까.","JPN":"確かにその通りだと思います。みんなもある程度は仕方ないことだと思っていましたし。","ENG":"They're not wrong. We've already given up in a way.","TWN":"沒錯，雖然大家都心知肚明，"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"하지만 매번 똑같은 팀, 똑같은 스폰서…… 조금 김빠지거든.","JPN":"だけど、毎回同じチーム、同じスポンサー……ちょっとつまらないよね。","ENG":"It's the same team, same sponsor every time... And it gets a little boring.","TWN":"但每次都是一樣的隊伍、一樣的贊助商……還是令人有點失望。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그런 암묵적인 분위기를 정면으로 박살내는 팀이 나타났는데……!","JPN":"そんな今までのお約束のような展開を、真正面からぶち壊してくれるチームが現れたのに……！","ENG":"But this year, a team appears out of nowhere, charging headfirst into this unwritten rule...!","TWN":"然而現在，出現一支打破這個局面的隊伍……！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"어떻게 두근거리지 않을 수 있겠냐고요!","JPN":"ワクワクせずにはいられないですよね！","ENG":"How can anyone not be excited?!","TWN":"這叫人怎麼能不興奮呢！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"상대는 그 그림자에게도 승리한 전승무패의 카운터! 오지만디아스!","JPN":"相手はあの、シャドウにも勝利した全勝無敗のカウンター！　オジマンディアス！","ENG":"On top of that, their opponent is the undefeated Counter that even beat that Shadow! Ozymandias!","TWN":"對手可是連那個暗影都要認輸的百戰百勝制裁者！奧茲曼迪亞斯！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"예상 승률은 소수점 미만! 분석된 전력 상으로는 패배가 당연합니다!","JPN":"予想される勝率は限りなくゼロに近く！　分析上の戦力では敗北が順当でしょう！","ENG":"Their expected victory probability is in the decimals! And according to analysis reports, their defeat is set in stone!","TWN":"她們贏的機率根本是微乎其微！從戰力分析來看，失敗也是理所當然的！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"단축형 돌격소총이 주무장인 카나리아 스쿼드에게는 4종 침식체나 다름없는 자연재해!","JPN":"騎兵銃がメイン武器であるカナリア・スクワッドにとっては第4種侵食体に匹敵する自然災害！","ENG":"Canary Squad's main weapon is a compact assault rifle, so the current champion is no different from a natural disaster the size of a Category 4 C.O.!","TWN":"對主要武器是單軸型突擊步槍金絲雀小隊來說，根本是無異於4類侵蝕體的自然災害！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"오지만디아스의 사복검은 공간 장악에 특화된 무기죠!","JPN":"オジマンディアスの蛇腹剣は空間掌握に特化した武器ですよね！","ENG":"Ozymandias' whip sword is also a weapon specialized in area domination!","TWN":"奧茲曼迪亞斯的蛇腹劍是擅於掌控空間的武器！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"300미터 넘는 공간을 장악할 만큼 늘어나면서, 태풍에 버금가는 순간 속도로 몰아치는 괴물! 근접전을 위해 접근하는 순간 필패입니다!","JPN":"伸縮で300メートルを超える空間を掌握し、嵐のような瞬間速度で襲ってくる怪物！　近接戦を仕掛けたとたんに負けが決まってしまいます！","ENG":"It extends to cover over 300 m of space, and its speed is comparable to that of a hurricane! As soon as one tries to take her on in close-quarter combat, they're done for!","TWN":"可延伸至掌控超過300ｍ的空間，而且是瞬間速度僅次於颱風的怪物！近距離戰是絕對行不通的。"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"하지만 여러분! 이 곳은 샤레이드! 이 곳은 건틀렛 리그입니다!","JPN":"ですがみなさん！　ここはシャレード！　ここはガントレットリーグです！","ENG":"Nevertheless, everyone! This is Charade! This is the Gauntlet League!","TWN":"但是各位！這裡是查雷德！這裡是聖鎧聯賽！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_MITCH_IN_TRAILER_1-2"},{"id":"L18_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"수많은 기적을 담아냈고, 피 흘리지 않아도 승리의 영광을 누리는 곳!","JPN":"数々の奇跡があり、誰も死なずに勝利の栄光を掴める、この場所！","ENG":"This is a place where many miracles have occurred and where victory can be achieved without bloodshed!","TWN":"這裡發生過無數奇蹟，在這裡不用流血就可以享受勝利的榮耀！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_MITCH_IN_TRAILER_2-2"},{"id":"L19_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그리고 기적을 딛고 온 아기새들이 왕을 향해 다시 전진합니다!","JPN":"そして奇跡に味方された小鳥たちは、王に向かってもう一度前進します！","ENG":"And in this moment, these two baby birds, who have already done the impossible, are inching closer to the queen!","TWN":"踩著奇蹟而來的小鳥們再次向女王前進！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_MITCH_IN_TRAILER_3-2"},{"id":"L20_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"과연! 광산에 끌려간 카나리아처럼 비참하게 쓰러질지! 새장을 박차고 화려하게 날아오를지!","JPN":"果たして！　鉱山に連れていかれたカナリアのように哀れな敗北を迎えるか！　鳥かごを打ち破り、華麗に飛翔するか！","ENG":"How will it end?! Will they die like the canaries that were dragged into the mines?! Or will they break free from their cage and soar up into the sky?!","TWN":"究竟她們是會像被帶到礦坑的金絲雀一樣悲慘地死去！還是會衝破鳥籠華麗地飛翔呢！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"기적은 이미 일어났습니다! 그리고 지금 도시의 모두가 한 마음으로, 더 큰 기적을 기대합니다!","JPN":"奇跡はすでに起きています！　そして今、都市中のみんなが、より大きな奇跡を見たいと願っています！","ENG":"A miracle has already happened once here! And now, the entire city has banded together to pray for another miracle!","TWN":"奇蹟曾經發生過！現在整座城市的人，都期待她們能創造出更大的奇蹟！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_CHEER_02"},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"카나리아 스쿼드──! 입장!!","JPN":"カナリア・スクワッド──！　入場！！","ENG":"Enter, CANARY SQUAD–!","TWN":"金絲雀小隊—！進場！！"},"stage":{"bg":"HELI_NIGHT_3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"조심해요!","JPN":"危ない！","ENG":"Watch out!","TWN":"小心！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"여기 환영식은 왜 이래? 언니 혹시 사춘기야?","JPN":"歓迎のし方がなんでいつもこうなわけ？　あんたってもしかして反抗期？","ENG":"What's with the welcome here? Are you going through puberty by chance?","TWN":"這裡的歡迎儀式是怎麼回事？姊姊你不會是叛逆期吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"고마워요, 노엘. 하마터면 당할 뻔했어요.","JPN":"ありがとうございます、ノエル。もう少しでやられるところでした。","ENG":"Thanks, Noelle. She almost got me.","TWN":"謝謝你，洛艾兒，我差點就被砍到了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"호오, 지금 내 검을 막아낸 거야? 콜드 케이스답게 튼튼하네.","JPN":"へえ、私の剣を受け止めたんだ？　さすがコールドケース、丈夫なのね。","ENG":"Ho-oh, did you just block my strike? Well, it's sturdy, as a Cold Case should be.","TWN":"喔呵，擋下我的劍嗎？不愧是Cold Case，很堅固呢。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하지만 그게 몇 번이나 널 지켜줄 수 있을까?","JPN":"でも、それがいつまであなたを守ってくれるかしらね？","ENG":"But I wonder how many more times it can protect you.","TWN":"但那個東西能保你幾次？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"밑바닥까지 떨어졌다가 다시 여기까지 올라온 건 좋은데 말이야.","JPN":"一度どん底まで落ちて、ここまで舞い戻ってきたのは素晴らしいけど。","ENG":"It's great how you made it back up here after hitting rock bottom.","TWN":"恭喜你們從跌落谷底後，又再次爬上來。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"후후, 그래서? 머리 좀 식히고 왔니, 루이즈?","JPN":"ふふ、それで？　少しは頭を冷やしてきた？　ルイーズ。","ENG":"Fu fuu. So, did you have enough time to cool off, Louisé?","TWN":"呵呵，所以呢，露易絲？你有想清楚再來嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"시간도 얼마 안 남았는데…. 슬슬 결판을 내야지.","JPN":"時間も残り僅か……そろそろ決着をつけないとね。","ENG":"There isn't much time left... We should end this soon.","TWN":"時間剩不多……是時候分出勝負了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"맞는 말이에요.","JPN":"その通りです。","ENG":"You're right.","TWN":"你說的沒錯。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그동안 저는 착각하고 있었어요.","JPN":"私はずっと思い違いをしていました。","ENG":"I've been mistaken up until now.","TWN":"我一直以來都搞錯方向。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"애초에 S급 카운터인 당신한테 정면대결로 이겨 먹겠다는 생각 자체가 틀렸던 거예요.","JPN":"そもそもSランクカウンターであるあなたに正面から勝とうなんて無理な話だったんです。","ENG":"I was naive to think that I could win against a grade S Counter in a fair fight.","TWN":"想和你這個S級制裁者正面對決的想法，打從一開始就是錯的。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래? 편법으로는 이길 수 있다는 이야기로 들리는데?","JPN":"そう？　姑息な手を使えば勝てるという話かしら？","ENG":"Oh? That just sounds like you're going to win by using some clever tactic on me.","TWN":"然後呢？意思是想改走旁門左道嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그러니 무구를 개방한 시점에서 저희의 패배입니다.","JPN":"ですので、武具を開放した時点で私たちの負けです。","ENG":"So, when I decided to unleash my Armament, it was already our defeat.","TWN":"因此當我決定開放武具的瞬間，其實就表示我們已經輸掉比賽。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그건 전장이 아닌 곳에서 사람을 겨눠서는 안 되는 물건이니까요.","JPN":"それは戦場以外で人に向けてはいけないものですから。","ENG":"That is something that should not be aimed at someone unless it is on the battlefield.","TWN":"因為那個東西只能被用在戰場上，而不是對準無辜的人。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그래서…….","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그래서 저 이번 리그에서 꼭 우승하고 싶어요!","JPN":"だから私は今回のリーグで絶対に優勝したいです！","ENG":"So that's why I want to win the Gauntlet!","TWN":"所以我很想在這次的聯賽中奪冠！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우승해서 펠리세트의 꿈을 이루는 데 보탬이 되고 싶어요!","JPN":"優勝して、フェリセットの夢を叶えるために、役に立ちたいです！","ENG":"I want to become the champion and help Félicette achieve her dream!","TWN":"我想奪得冠軍，好幫助費莉塞特實現夢想！"},"stage":{"bg":"HIGHWAY_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"네가 챔피언이랑 무슨 관계든 그런 건 내 알 바 아니야.","JPN":"お前がチャンピオンとどういう関係だろうと、知ったこっちゃない。","ENG":"Your relationship with the champion is none of my business.","TWN":"無論你和冠軍是什麼關係，都不關我的事。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까 이겨. 반드시 이겨서 저 여자 낯짝이 일그러지는 걸 보여 주자고.","JPN":"だから勝て。必ず勝ってあの女の顔が歪むところを見ようぜ。","ENG":"But I want you to win. Win and show the world her ugly, defeated mug.","TWN":"你一定要贏，讓大家看看她的醜態。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나는 자네가 여기까지 오면서, 뭔가 느끼는 게 있을 거라고 생각했어.","JPN":"君がここまでたどり着く中で、何か気づいてくれると思った。","ENG":"I had thought you would feel something as you reached this point.","TWN":"我以為你一路走到這裡，應該有感受到什麼。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 자네가 뭘 하고 싶은지 들은 뒤에도 계속 도와준 걸세.","JPN":"だからこそ君の目的を知った後も、協力し続けた。","ENG":"That is why I kept helping you even after hearing what you wanted to do.","TWN":"所以當我聽到你想的事時，我依然選擇幫助你。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니 대답해 보게.","JPN":"その上で聞かせてくれ。","ENG":"So, answer this one question.","TWN":"所以，回答我。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오지만디아스를 죽이지 못한 게 분한 건가?","JPN":"オジマンディアスを殺せなかったことが悔しいのか？","ENG":"Does your anger come from not having killed Ozymandias?","TWN":"讓你憤怒的，是因為沒能殺死奧茲曼迪亞斯嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"맞아요, 이건 건틀렛이니까요. 실전이 아니에요.","JPN":"そうです、これはガントレットであり、実戦ではありません。","ENG":"Yes, this is the Gauntlet. It's not a real battle.","TWN":"是的，這裡是聖鎧，不是實戰。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그리고 건틀렛에서는 상대의 목숨을 빼앗아서는 안 돼요. 그러면 오히려 지는 거죠.","JPN":"そしてガントレットでは相手の命を奪うことは許されていません。そうするとむしろ負けてしまいます。","ENG":"And in the Gauntlet, we are forbidden to take another's life. That only leads to defeat.","TWN":"在聖鎧是不可以奪走對方性命的，那麼做反而會輸。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"흐음, 무슨 말을 하고 싶은 거야? 벌써 트레이너라도 되고 싶어졌어?","JPN":"ふーん？　何が言いたいのかしら？　トレーナーにでもなりたくなった？","ENG":"Hmm, what are you trying to say? Have you already shifted your dreams to becoming a trainer?","TWN":"嗯哼，你到底想說什麼？這麼快就想當教練啦？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"모두가 도와 준 덕분에 비로소 깨달을 수 있었어요. 오지만디아스.","JPN":"みんなに助けられて、やっと気づくことができたんです。オジマンディアス。","ENG":"I was finally able to realize it thanks to everyone helping me, Ozymandias.","TWN":"多虧有大家的幫忙，我才能領悟到這些，奧茲曼迪亞斯。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그리고…… 이게 내 복수야!","JPN":"そして……これが私の復讐よ！","ENG":"And this... this will be how I get my revenge!","TWN":"還有……這就是我的報仇！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_05"},{"id":"L27_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"옥상을 날려 버렸잖아? 무슨 생각이지?","JPN":"屋上を吹っ飛ばした？　どういうつもり？","ENG":"She just blew the roof off? What is she thinking?","TWN":"直接把頂樓炸飛？你到底想做什麼？"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"잠깐, 나를 향해서 콜드 케이스를 쏜 게 아니야?","JPN":"待って、コールドケースで攻撃したのは私じゃない？","ENG":"Wait, she didn't fire the Cold Case at me?","TWN":"等等，Cold Case瞄準的似乎不是我？"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"표적이…… 빌딩 그 자체라면…….","JPN":"標的が……ビルそのものだとしたら……","ENG":"If her target... was the building itself...","TWN":"如果目標……是大樓本身……"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"설마…… 물리 법칙을 역전시키려고?","JPN":"まさか……物理法則を逆転させるのが狙い？","ENG":"What...? Is she trying to reverse the laws of physics?","TWN":"難道……是想逆轉物理定律？"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"루이즈! 설마 동반자살이라도 하려는 생각은 아니겠지?!","JPN":"ルイーズ！　まさか心中でもしようっていうわけじゃないわよね！？","ENG":"Louisé! You're not thinking of committing double suicide, are you?!","TWN":"露易絲！你不會是想和我同歸於盡吧？！"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"이런다고 겁 먹을 줄 알았다면……!","JPN":"こんなので私が怯えると思ったら……！","ENG":"If you think that's going to scare me...!","TWN":"你以為你這麼做我就會怕你嗎……！"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……역시 위력이 훨씬 약해졌어.","JPN":"……やっぱり威力が激減しているわ。","ENG":"...Just as I expected. Your power's gotten weaker.","TWN":"……威力果然變弱許多。"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"何ですって？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"큭……! 대체 이게 무슨!?","JPN":"くっ……！　いったいこれは！？","ENG":"Kgh...! What's the meaning of this?!","TWN":"咳……！這到底怎麼回事？！"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"당신의 사슬검은 카운터가 사용하는 무기 중에서도 무척 다루기 어려운 형태예요.","JPN":"あなたの蛇腹剣はカウンターが使用する武器の中でも、特に扱いが難しい形をしています。","ENG":"Your whip sword is a weapon that's extremely difficult to use, even for a Counter.","TWN":"在制裁者使用的武器當中，你的鏈劍特別難操作。"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"균형을 잡으려면 양 발이 지면에 닿아 있어야 하죠.","JPN":"バランスを取るためには、両足が地面についていなければいけませんよね。","ENG":"In order to use it properly, the user must have both feet placed on the ground.","TWN":"要想保持平衡，雙腳就必須接觸地面吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"균형을 잡을 수 없는 상태에서는 공격의 위력도 급감하고요.","JPN":"バランスが取れていない状態では攻撃の威力も激減しますから。","ENG":"Without being able to balance oneself, the sword's effectiveness sharply declines.","TWN":"在無法保持平衡的狀態下，攻擊的威力會驟減。"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그걸, 그런 걸 네가 어떻게……!?","JPN":"そんな、それをなぜあんたが……！？","ENG":"H-how do you know that...?!","TWN":"你，你怎麼會知道……？！"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"전승무패 관리국 공인 S급 카운터 오지만디아스…….","JPN":"全勝無敗、管理局公認のSランクカウンター、オジマンディアス……","ENG":"The undefeated, Administration confirmed Grade S Counter, Ozymandias...","TWN":"百戰百勝，管理局公認的S級制裁者，奧茲曼迪亞斯……"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그 커리어에 제대로 된 <color=#ffd34c>공중전</color>은 단 한 번도 없었어.","JPN":"そのキャリアの中でまともな<color=#ffd34c>空中戦</color>は一度もない。","ENG":"Of your entire career, you've never engaged in any proper <color=#ffd34c>aerial battles</color>.","TWN":"輝煌的戰績中，卻從來沒有過<color=#ffd34c>空戰</color>。"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그건 누구보다 당신의 팬이었던 내가 제일 잘 알아!","JPN":"それは誰よりもあなたのファンだった私が一番良く知っているわ！","ENG":"I would know, because I was your biggest fan!","TWN":"身為你曾經的粉絲，我比任何一個人都清楚這件事！"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그런 말도 안 되는 추측만으로 도박을 건다고? 너 제정신이야!?","JPN":"そんなバカみたいな推測だけで賭けに出たってこと？　あなた正気なの！？","ENG":"You gambled everything on an absurd assumption? You must be out of your mind!","TWN":"光是這樣憑空推測就敢賭一把？你腦袋有問題嗎？！"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"도박이 아니라 승부수야! 여기서 증명해 줄 테니까!","JPN":"賭けじゃなくて勝利のための一手よ！　ここで証明してあげるわ！","ENG":"It's a gambit, not a gamble! I'll prove it right now!","TWN":"這不是賭，這是必勝的戰術！我會在這裡證明給你看！"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"당신이…… 공중전에서는 삼류 이하라는 걸!","JPN":"あなたが……空中戦では三流以下だってね！","ENG":"That in aerial battles... you're no better than a third-grade player!","TWN":"證明……你在空戰中根本連三流的邊都搭不上！"},"stage":{"bg":"SKY_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};